-- ===================================================
-- pds 테이블 (제품소개/다운로드 게시판)
-- ===================================================
CREATE TABLE pds (
    pds_id         INT AUTO_INCREMENT PRIMARY KEY          COMMENT '제품 ID',
    title          VARCHAR(200) NOT NULL                   COMMENT '제목',
    content        TEXT                                    COMMENT '내용',
    os_info        VARCHAR(100) DEFAULT 'Windows 10/11 호환 설치 패키지' COMMENT 'OS 구분',
    version        VARCHAR(20)                             COMMENT '프로그램 버전',
    file_size      VARCHAR(20)                             COMMENT '용량',
    download_count INT          DEFAULT 0                  COMMENT '다운로드 횟수',
    thumbnail      VARCHAR(255)                            COMMENT '썸네일 파일명 (C:/mm-file/pds/)',
    download_url   VARCHAR(500)                            COMMENT '다운로드 URL',
    category       VARCHAR(20)  DEFAULT 'software'         COMMENT '구분 (software/utility/manual)',
    sort_order     INT          DEFAULT 0                  COMMENT '표시 순서',
    published_at   DATE                                    COMMENT '게시일자',
    is_active      CHAR(1)      DEFAULT 'Y'               COMMENT '활성화 여부 (Y/N)',
    reg_date       DATETIME     DEFAULT CURRENT_TIMESTAMP  COMMENT '등록일',
    update_date    DATETIME     DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일'
) COMMENT '제품소개 다운로드 게시판 new';

-- ===================================================
-- 초기 데이터 INSERT (현재 화면 기준, 다운로드수 100)
-- ===================================================
INSERT INTO pds (title, content, os_info, version, file_size, download_count, thumbnail, download_url, category, sort_order, published_at) VALUES
('[여러사람8.2] 고객관리 -5자리우편번호,도로명주소 적용',
'***** 설치방법\n[다운로드]를 눌러 "현재위치에서 실행" 또는 "열기" 선택\n*설치 중간에 나올 수 있는 등록오류는 <무시>를 누르시면 됩니다.\n\n1. 가 격 : 문의 요망\n\n2. 주요성능 :\n고객을 효율적으로 관리해주는 고객관리 전문 프로그램 여러사람 v8.2 입니다.\n새 도로명 주소 및 개정된 우편번호와 전화지역번호 데이타 베이스를 가지고 있어서 편리하게 이용 할 수 있습니다.\n고객 입력폼에는 입력일자를 포함하여 성명, 직책, 주소, 회사/부서, 전화, 팩스, 휴대폰, e-mail, 비고, 그룹등 다양한 폼이 준비가 되어 있습니다.\n강력한 서치 엔진을 내장하여 입력 폼의 내용중 하나의 조건으로 빠르게 검색이 가능합니다.\n복합 검색이 가능하며 전화를 소프트웨어로 바로 걸어줄 수도 있습니다(LG UPlus 기업인터넷전화 가입시).\n특히 다양한 인쇄 옵션을 제공하여 우편 및 DM 발송에 편리한 여러 가지 기능을 제공합니다.',
'Windows 10/12 호환 설치 패키지', 'v8.2', '15MB', 100, '1.jpg', 'https://www.mmsoft.co.kr/program/man.exe', 'software', 1, '2026-03-10'),

('주택/빌라 관리비 정산 소프트웨어',
'설치방법 : [다운로드]를 눌러 "현재위치에서 실행" 또는 "열기" 선택\n*설치 중간에 나올 수 있는 등록오류는 <무시>를 누르시면 됩니다.\n\n1. 가 격 : 문의요망\n\n2. 주요성능 :\n· 주택이나 빌라 관리비 정산 소프트웨어\n· 전기료(공동, 세대)\n· 수도료(전월, 현월, 톤당요금, 사용량기록)\n· 이월미납금 포함하여 잔액계산\n· 관리비명세서 출력\n· 호별 월사용리스트 출력\n· 입주자 현황 출력\n· 유선방송, 정화조요금, 수선비, 음식물수거비등 기타항목 정의가능\n· 세대별, 전체 문자메시지 전송가능\n· 지로출력-MICR용지, OCR용지 모두 사용 가능\n\n3. OS : Windows 95/98/NT/2000/2003/XP/Vista',
'Windows 10/14 호환 설치 패키지', 'v1.0', '9MB', 100, '2.jpg', 'https://www.mmsoft.co.kr/program/SetupJiroJu.exe', 'software', 2, '2026-03-10'),

('[지로출력도우미4.1] 고객관리 및 지로용지출력',
'***** 설치방법\n[다운로드]를 눌러 "현재위치에서 실행" 또는 "열기" 선택\n*설치 중간에 나올 수 있는 등록오류는 <무시>를 누르시면 됩니다.\n\n1. 가 격 : 문의요망\n\n2. 주요성능 :\n· 월별 금액 한꺼번에 입력 가능\n· 새 도로명주소와 구주소 모두 입력가능\n· MICR용지, OCR용지 모두 사용 가능\n· 입금자동 체크\n· 월별납입/미납자 리스트 출력 가능\n· 화일단위로 분류하여 입출력 가능\n· 입력시 회원번호 자동 증가\n· 새우편번호 5자리 적용\n· 집배코드 인쇄 및 집계표 작성(옵션)\n· 64비트에서 검색오류 수정됨\n· 범위선택 및 모두선택 인쇄 가능\n\n3. OS : Windows 95/98/NT/2000/2003/XP/Vista/7',
'Windows 10/15 호환 설치 패키지', 'v4.1', '17MB', 100, '3.jpg', 'https://www.mmsoft.co.kr/program/jiro.exe', 'software', 3, '2026-03-10'),

('<무료> [여러사람프리웨어v7.5]',
'설치방법 : [다운로드]를 눌러 "현재위치에서 실행" 또는 "열기" 선택\n*설치 중간에 나올 수 있는 등록오류는 <무시>를 누르시면 됩니다.\n\n1. 본 프로그램은 1997년부터 판매용으로 제작된 프로그램이며 5천여 업체에서 구매해 주셨습니다. 2012년 당시 88,000원에 정상판매되던 제품입니다. 그동안 성원에 보답하고, 보다 많은 분들께 편의를 제공하고자 무료 버젼으로 전환하였습니다.\n\n2. 모든 기능은 정품과 같습니다.\n- 기존 구매 고객분들은 별도로 정식번호 등록을 해야 하는 불편이 없어졌습니다.\n\n3. 단, 기존 구매해주신 고객님과 신규 도입을 원하시는 분들께 불공평한 점은 있습니다. 이해해 주시기 바랍니다.\n\n4. 문의 바랍니다.\n저희에게 무료로 전환하면서 바라는 것은 저희 메뉴얼 서비스를 이용해 주셨으면 합니다. 메뉴얼 서비스를 구독해주시면 문자(90건), 문자(2000건)의 메뉴얼 서비스와 단체 회비(대기업)등의 서비스를 제공합니다.',
'Windows 10/17 호환 설치 패키지', 'v7.5', '12MB', 100, '4.jpg', 'https://www.mmsoft.co.kr/program/man745.exe', 'software', 4, '2026-03-10'),

('<프리웨어> 아카데미플러스 - 학원/체육관/헬스장',
'설치방법 : [다운로드]를 눌러 "현재위치에서 실행" 또는 "열기" 선택\n*설치 중간에 나올 수 있는 등록오류는 <무시>를 누르시면 됩니다.\n\n제품버젼: 아카데미플러스 V2017\n제품가격: 무료\n사용환경: Windows 95/98/NT/2000/2003/XP/Vista\n\n주요기능\n1. 학원생 정보 관리\n2. 카드(마그네틱)를 이용한 출석 관리\n3. 카드 긁으면 출석되었다는 메세지와 함께 학원생 신상정보가 보임\n4. 발신자 표시기를 이용해 전화가 오면 수강생 정보가 출력됨\n5. 가정통신문 같은 파일 첨부\n6. 이메일 발송\n7. 이메일 첨부파일에서 전체/부분적 다르게 보낼 수 있음\n8. 출석 기준에 따른 재원생 목록 조회\n9. 생일/기념일 이벤트 발생시 처리\n10. 자동/수동 출석 관리 및 출석체크 처리\n11. 각 학원생의 월/년 출석 현황을 한눈에 볼 수 있는 달력에 표시\n12. 학원생에 대한 문의 처리\n13. 학원생에 대한 메모 처리\n14. SMS 단체 메시지 발송가능\n15. 전체 이미지를 검색하는 기능',
'Windows 10/19 호환 설치 패키지', 'v1.0', '15MB', 100, '5.jpg', 'https://www.mmsoft.co.kr/program/setupaca.exe', 'software', 5, '2026-03-10'),

